INSERT INTO public.m_cases (title, student_name, metrics, header, sub, problem, action, description, order_index, is_active) VALUES
('Фотограф (Услуги)', 'Николай А.', '75к → 130к за 2 недели', '+55 000 ₽ за 14 дней', 'Как выйти из ловушки низкого чека, перестав "охотиться" за новыми клиентами.', 'Продажа услуги за 10к в лоб приносила мало заказов, база лежала "мёртвым грузом".', 'Запущен "мягкий вход" — продукт "Фото-подружка" (съемка на смартфон + ИИ-ретушь).', 'База превратилась в актив, поток продаж без вложений в трафик.', 10, true),
('Школа языков (Образование)', 'Language School', 'Заполнение групп на 1/3 без трафика', '+30% новых студентов', 'Как перестать зависеть от рекламных бюджетов и найти деньги в расписании.', 'Простой учебных классов и база "отказников", которым продукт казался тяжелым.', 'В пустые часы встроили разговорные клубы — доступный шаг для базы.', 'Простаивающее время стало активом, +30% учеников за 60 дней.', 20, true),
('Инвест-недвижимость (Коллаборации)', 'Investment Real Estate', 'Доступ к VIP-клиентам + прибыль', 'Новая премиум-аудитория', 'Как превратить одно знакомство в систему взаимных продаж.', 'Поиск целевых клиентов через стандартные каналы обходился слишком дорого.', 'Коллаборация с премиум-брендом косметики: подарки и сертификаты взаимно.', 'Прибыль от продаж партнера и качественная аудитория с высоким чеком.', 30, true),
('MLM-бизнес (Сетевой)', 'MLM Network', 'Скачок оборота за 14 дней', '+60 000 ₽ и +15 партнеров', 'Как расти через раскрытие экспертных ресурсов внутри своей же сети.', 'Команда рассматривалась как "список имен", ресурсы партнеров не использовались.', 'Коллаборация с нутрициологом из числа партнеров — новые точки доверия.', 'Рост личных продаж и команды через активацию "спящей" среды.', 40, true),
('Юрист (Экспертный бизнес)', 'Lawyer Office', '80к+ без рекламного бюджета', '10 обращений вместо 1', 'Как перестать сливать бюджет и начать продавать через "входной сервис".', 'Расходы на рекламу 50к приносили 1 клиента; отсутствие системы входа.', 'Свободные окна загрузили "аудитом договоров" за 5 000 ₽.', 'Количество обращений выросло в 10 раз, стабильный доход без вложений.', 50, true),
('BBQ-оборудование (Товарный VIP)', 'VIP BBQ Gear', 'Активация базы с чеком 500к+', 'Допродажи на VIP-сегменте', 'Как превратить сервисную поддержку в мощный канал продаж.', 'Игнорирование базы клиентов после совершения крупной сделки.', 'Бесплатный сервисный осмотр оборудования для выявления новых потребностей.', 'Сервис стал точкой входа в допродажи тандыров и аксессуаров.', 60, true);
